    #[test]
    fn test_basic_put_get() {
        let cache = LruCache::new(2);
        assert_eq!(cache.put(1, "a".to_string()), None);
        assert_eq!(cache.put(2, "b".to_string()), None);
        assert_eq!(cache.get(&1), Some("a".to_string()));
