import { Redis } from 'ioredis';

interface RateLimiterOptions {
  maxRequests: number;
  windowSeconds: number;
}

interface RateLimitResult {
  allowed: boolean;
  remaining: number;
  resetAt: number;
}

class RateLimiter {
  private redis: Redis;
  private maxRequests: number;
  private windowSeconds: number;

  // Lua script for atomic rate limiting with pruning
  private static readonly LUA_SCRIPT = `
    local key = KEYS[1]
    local max_requests = tonumber(ARGV[1])
    local window_seconds = tonumber(ARGV[2])
    local now = tonumber(redis.call('TIME')[1])
    local window_start = now - window_seconds

    -- Remove entries outside the current window
    redis.call('ZREMRANGEBYSCORE', key, '-inf', window_start)

    -- Count remaining valid entries
    local count = redis.call('ZCARD', key)

    -- Check if we can allow a new request
    local allowed = 0
    if count < max_requests then
      -- Add current timestamp as a new entry
      redis.call('ZADD', key, now, now)
      allowed = 1
    end

    -- Calculate remaining and reset_at
    local remaining = max_requests - count - allowed
    if remaining < 0 then remaining = 0 end
    local reset_at = now + window_seconds

    return {allowed, remaining, reset_at}
  `;

  constructor(redis: Redis, options: RateLimiterOptions) {
    this.redis = redis;
    this.maxRequests = options.maxRequests;
    this.windowSeconds = options.windowSeconds;
  }

  async allow(key: string): Promise<RateLimitResult> {
    const result = await this.redis.eval(
      RateLimiter.LUA_SCRIPT,
      1,
      `ratelimit:${key}`,
      this.maxRequests.toString(),
      this.windowSeconds.toString()
    ) as [number, number, number];

    return {
      allowed: result[0] === 1,
      remaining: result[1],
      resetAt: result[2]
    };
  }

  async remaining(key: string): Promise<number> {
    const now = await this.getRedisTime();
    const windowStart = now - this.windowSeconds;

    // Prune old entries and count
    await this.redis.zremrangebyscore(`ratelimit:${key}`, '-inf', windowStart);
    const count = await this.redis.zcard(`ratelimit:${key}`);

    return Math.max(0, this.maxRequests - count);
  }

  async resetAt(key: string): Promise<number> {
    const now = await this.getRedisTime();
    return now + this.windowSeconds;
  }

  private async getRedisTime(): Promise<number> {
    const time = await this.redis.time();
    return parseInt(time[0], 10);
  }
}
