```go
package boundedworkerpool

import (
	"context"
	"errors"
	"fmt"
	"sync"
	"sync/atomic"
)

// ErrPoolFull is returned by Submit when the pool is saturated and the queue is full.
var ErrPoolFull = errors.New("pool is full")

// Stats represents a consistent snapshot of pool metrics.
type Stats struct {
	InFlight        int
	QueueDepth      int
	TotalSubmitted  int64
	TotalCompleted  int64
	TotalPanics     int64
	TotalRejected   int64
}

// BoundedWorkerPool is a fixed-size worker pool with bounded queue.
type BoundedWorkerPool struct {
	workers      int
	queueSize    int

	// counters (atomic for lock-free reads)
	totalSubmitted  int64
	totalCompleted  int64
	totalPanics     int64
	totalRejected   int64

	// state
	mu            sync.Mutex
	queue         []func() error
	inFlight      int
	shutdown      bool
	shutdownCtx   context.Context
	shutdownCancel context.CancelFunc

	// channels for worker communication
	taskCh       chan func() error
	done         chan struct{}
}

// New creates a new BoundedWorkerPool with W workers and a queue of given size.
func New(workers, queueSize int) *BoundedWorkerPool {
	if workers <= 0 {
		panic("workers must be positive")
	}
	if queueSize < 0 {
		panic("queueSize must be non-negative")
	}

	p := &BoundedWorkerPool{
		workers:   workers,
		queueSize: queueSize,
		queue:     make([]func() error, 0, queueSize),
		taskCh:    make(chan func() error, workers), // small internal channel for workers
		done:      make(chan struct{}),
	}

	// Start workers
	for i := 0; i < workers; i++ {
		go p.worker(i)
	}

	return p
}

// Submit submits a task to the pool. Returns a channel that will receive the error
// (or nil on success) and an error indicating if the pool was full.
func (p *BoundedWorkerPool) Submit(ctx context.Context, task func() error) (<-chan error, error) {
	// Check if pool is full without blocking
	p.mu.Lock()
	if p.shutdown {
		p.mu.Unlock()
		return nil, errors.New("pool is shut down")
	}
	if len(p.queue) >= p.queueSize {
		p.mu.Unlock()
		atomic.AddInt64(&p.totalRejected, 1)
		return nil, ErrPoolFull
	}
	// Add to queue
	p.queue = append(p.queue, task)
	atomic.AddInt64(&p.totalSubmitted, 1)
	p.mu.Unlock()

	// Create result channel
	resultCh := make(chan error, 1)

	// Try to send to worker immediately if possible
	select {
	case p.taskCh <- func() error {
		return p.executeTask(ctx, task, resultCh)
	}:
		return resultCh, nil
	default:
		// Queue is full or workers busy, task is in queue
		return resultCh, nil
	}
}

// executeTask runs a task and handles panics.
func (p *BoundedWorkerPool) executeTask(ctx context.Context, task func() error, resultCh chan error) error {
	defer func() {
		if r := recover(); r != nil {
			atomic.AddInt64(&p.totalPanics, 1)
			resultCh <- fmt.Errorf("panic: %v", r)
		}
	}()

	// Check if context is done before starting
	select {
	case <-ctx.Done():
		return ctx.Err()
	default:
	}

	err := task()
	atomic.AddInt64(&p.totalCompleted, 1)
	resultCh <- err
	return err
}

// worker is a single worker goroutine.
func (p *BoundedWorkerPool) worker(id int) {
	for {
		select {
		case <-p.done:
			return
		case taskFunc := <-p.taskCh:
			// Execute the task (it handles its own result channel)
			taskFunc()
		}
	}
}

// Shutdown drains in-flight tasks, refuses new ones, and returns after either
// all in-flight tasks complete or ctx is done.
func (p *BoundedWorkerPool) Shutdown(ctx context.Context) error {
	p.mu.Lock()
	if p.shutdown {
		p.mu.Unlock()
		return errors.New("pool already shut down")
	}
	p.shutdown = true
	p.shutdownCtx = ctx
	p.shutdownCancel, _ = context.WithCancel(ctx)
	p.mu.Unlock()

	// Close the done channel to stop workers
	close(p.done)

	// Wait for all in-flight tasks to complete or context to be done
	p.mu.Lock()
	inFlight := p.inFlight
	queueLen := len(p.queue)
	p.mu.Unlock()

	// If there are no in-flight tasks and no queued tasks, we're done
	if inFlight == 0 && queueLen == 0 {
		return nil
	}

	// Create a channel to track completion
	done := make(chan struct{})
	go func() {
		defer close(done)
		// Process remaining queued tasks
		for {
			p.mu.Lock()
			if len(p.queue) == 0 && p.inFlight == 0 {
				p.mu.Unlock()
				return
			}
			// Take a task from queue if any
			var task func() error
			if len(p.queue) > 0 {
				task = p.queue[0]
				p.queue = p.queue[1:]
				p.inFlight++
				p.mu.Unlock()

				// Execute task
				resultCh := make(chan error, 1)
				p.executeTask(p.shutdownCtx, task, resultCh)
				// Wait for result (task handles its own completion)
				<-resultCh
			} else {
				p.mu.Unlock()
				// No tasks, wait for workers to finish
				return
			}
		}
	}()

	select {
	case <-ctx.Done():
		return ctx.Err()
	case <-done:
		return nil
	}
}

// Stats returns a consistent snapshot of pool metrics.
func (p *BoundedWorkerPool) Stats() Stats {
	// To get a consistent snapshot, we need to read all counters atomically
	// and also get the current queue depth and in-flight count under the mutex.
	p.mu.Lock()
	stats := Stats{
		InFlight:        p.inFlight,
		QueueDepth:      len(p.queue),
		TotalSubmitted:  atomic.LoadInt64(&p.totalSubmitted),
		TotalCompleted:  atomic.LoadInt64(&p.totalCompleted),
		TotalPanics:     atomic.LoadInt64(&p.totalPanics),
		TotalRejected:   atomic.LoadInt64(&p.totalRejected),
	}
	p.mu.Unlock()
	return stats
}
```

## Explanation of Stats() Consistency

The `Stats()` method provides a consistent snapshot by using a combination of atomic operations and mutex protection:

1. **Atomic Counters**: `TotalSubmitted`, `TotalCompleted`, `TotalPanics`, and `TotalRejected` are updated using `atomic.AddInt64()` and read using `atomic.LoadInt64()`. This ensures lock-free reads for these high-throughput counters.

2. **Mutex-Protected State**: `InFlight` and `QueueDepth` are protected by the pool's mutex (`p.mu`). These values are read while holding the mutex to ensure consistency.

3. **Consistent Snapshot**: When `Stats()` is called, we first acquire the mutex to read `InFlight` and `QueueDepth`. While holding the mutex, we also read the atomic counters. This ensures that all values are from the same point in time, preventing "torn reads" where the queue depth might change between reading different counters.

The key insight is that we read the mutex-protected state and atomic counters together under the mutex, providing a consistent view of the pool at that instant. The atomic counters could be read without the mutex, but reading them together with mutex-protected state ensures a consistent snapshot.

## Key Design Decisions

1. **Non-blocking Submit**: `Submit` checks the queue length under the mutex and returns immediately if full, without blocking.

2. **Panic Handling**: Panics in tasks are caught by `recover()` in `executeTask` and converted to errors on the result channel.

3. **Zero Goroutine Leaks**: When `Shutdown` is called, the `done` channel is closed, causing all workers to exit. The only remaining goroutine is the one that called `Shutdown`.

4. **Result Channels**: Each task gets its own result channel, ensuring that errors are delivered correctly even with concurrent tasks.
